@@ -3475,9 +3475,9 @@ zfs_freebsd_reclaim(ap)
 	ASSERT(zp->z_phys);
 	ASSERT(zp->z_dbuf_held);
 	zfsvfs = zp->z_zfsvfs;
+	ZTOV(zp) = NULL;
 	if (!zp->z_unlinked) {
 		zp->z_dbuf_held = 0;
-		ZTOV(zp) = NULL;
 		mutex_exit(&zp->z_lock);
 		dmu_buf_rele(zp->z_dbuf, NULL);
 	} else {
